func (v SpecValue) Equal(o attr.Value) bool {
	other, ok := o.(SpecValue)

	if !ok {
		return false
	}

	if v.state != other.state {
		return false
	}

	if v.state != attr.ValueStateKnown {
		return true
	}

	if !v.AaaServers.Equal(other.AaaServers) {
		return false
	}

	if !v.NodeGroupSelectors.Equal(other.NodeGroupSelectors) {
		return false
	}

	if !v.NodeGroups.Equal(other.NodeGroups) {
		return false
	}

	if !v.Radius.Equal(other.Radius) {
		return false
	}

	if !v.RouterKind.Equal(other.RouterKind) {
		return false
	}

	if !v.Tacacs.Equal(other.Tacacs) {
		return false
	}

	if !v.TimeoutSeconds.Equal(other.TimeoutSeconds) {
		return false
	}

	if !v.SpecType.Equal(other.SpecType) {
		return false
	}

	return true
}

